Contents of file frontend/src/lib/api.ts:

1 | /**
2 |  * Typed client for the AutorIA REST API (docs/api_contract.yaml).
3 |  * All response shapes mirror the contract via lib/types.ts — never invent fields here.
4 |  */
5 | import type {
6 |   AuthorSummary,
7 |   DocumentUploadAccepted,
8 |   StyleProfile,
9 | } from "@/lib/types";
10 | 
11 | /**
12 |  * Thrown when a style-profile request returns HTTP 404.
13 |  * Per contract: 404 means "author unknown OR StyleProfile not yet computed"
14 |  * — this is an EMPTY state, not a server error. Callers must distinguish it
15 |  * from NetworkError / 5xx (which are error states with retry).
16 |  */
17 | export class NotFoundError extends Error {
18 |   readonly status = 404 as const;
19 |   constructor(label: string) {
20 |     super(`${label} returned 404 (not found or not yet computed)`);
21 |     this.name = "NotFoundError";
22 |   }
23 | }
24 | 
25 | const API_BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000";
26 | 
27 | async function parseOrThrow<T>(res: Response, label: string): Promise<T> {
28 |   if (!res.ok) {
29 |     throw new Error(`${label} failed with status ${res.status}`);
30 |   }
31 |   return res.json() as Promise<T>;
32 | }
33 | 
34 | /** GET /api/authors — preloaded authors plus any added via document upload. */
35 | export async function listAuthors(): Promise<AuthorSummary[]> {
36 |   const res = await fetch(`${API_BASE}/api/authors`, { cache: "no-store" });
37 |   return parseOrThrow<AuthorSummary[]>(res, "GET /api/authors");
38 | }
39 | 
40 | /**
41 |  * POST /api/authors/{author_id}/documents — multipart .txt/.md upload (202 async).
42 |  *
43 |  * CONTRACT GAP: the API has no create-author endpoint, yet listAuthors is
44 |  * documented as returning authors "added via document upload". The add-author
45 |  * flow therefore posts to a fresh slug and expects the backend to auto-create
46 |  * it; the contract's 404 for unknown author_id contradicts this. Flagged for
47 |  * the Sprint 1 contract pairing session.
48 |  */
49 | export async function uploadAuthorDocument(
50 |   authorId: string,
51 |   file: File,
52 |   title?: string,
53 | ): Promise<DocumentUploadAccepted> {
54 |   const form = new FormData();
55 |   form.append("file", file);
56 |   if (title) form.append("title", title);
57 |   const res = await fetch(
58 |     `${API_BASE}/api/authors/${encodeURIComponent(authorId)}/documents`,
59 |     { method: "POST", body: form },
60 |   );
61 |   return parseOrThrow<DocumentUploadAccepted>(
62 |     res,
63 |     "POST /api/authors/{id}/documents",
64 |   );
65 | }
66 | 
67 | /**
68 |  * GET /api/authors/{author_id}/style-profile — Style DNA fingerprint v1.0.
69 |  *
70 |  * Throws NotFoundError for HTTP 404 (author unknown or profile not yet computed).
71 |  * Throws a plain Error for any other non-ok status (5xx, network failure, etc.).
72 |  */
73 | export async function getStyleProfile(authorId: string): Promise<StyleProfile> {
74 |   const res = await fetch(
75 |     `${API_BASE}/api/authors/${encodeURIComponent(authorId)}/style-profile`,
76 |     { cache: "no-store" },
77 |   );
78 |   if (res.status === 404) {
79 |     throw new NotFoundError(`GET /api/authors/${authorId}/style-profile`);
80 |   }
81 |   return parseOrThrow<StyleProfile>(
82 |     res,
83 |     `GET /api/authors/${authorId}/style-profile`,
84 |   );
85 | }
86 | 
87 | /** Derives a URL-safe author slug from a display name (client-side id proposal). */
88 | export function slugifyAuthorName(name: string): string {
89 |   return name
90 |     .normalize("NFD")
91 |     .replace(/[\u0300-\u036f]/g, "")
92 |     .toLowerCase()
93 |     .replace(/[^a-z0-9]+/g, "-")
94 |     .replace(/^-+|-+$/g, "");
95 | }
