1 | import { Clock, TriangleAlert } from "lucide-react";
2 | 
3 | import { DistinctiveVocabHighlight } from "@/components/DistinctiveVocabHighlight";
4 | import { FitScoreBar, FitScoreBarPending } from "@/components/FitScoreBar";
5 | import { Button } from "@/components/ui/button";
6 | import { en } from "@/lib/i18n/en";
7 | import type { GenerationOutput } from "@/lib/types";
8 | import { cn } from "@/lib/utils";
9 | 
10 | /**
11 |  * Async state for one generation branch. Every column renders exactly one of
12 |  * these — there is no path that shows a spinner forever (timeout is a state).
13 |  */
14 | export type GenerationState =
15 |   | { status: "loading" }
16 |   | { status: "timeout" }
17 |   | { status: "error" }
18 |   | { status: "success"; output: GenerationOutput };
19 | 
20 | type AuthorColumnProps = {
21 |   state: GenerationState;
22 |   onRetry?: () => void;
23 | } & (
24 |   | { variant: "vanilla" }
25 |   | {
26 |       variant: "authorial";
27 |       authorId: string;
28 |       authorName: string;
29 |       distinctiveTerms?: readonly string[];
30 |     }
31 | );
32 | 
33 | /**
34 |  * One side of the vanilla-vs-AutorIA comparison. The authorial column wears
35 |  * the author's signature palette (via data-voice); the vanilla column stays
36 |  * deliberately anonymous — that asymmetry is the 5-second contrast device.
37 |  */
38 | export function AuthorColumn(props: AuthorColumnProps) {
39 |   const isVoice = props.variant === "authorial";
40 |   const { state } = props;
41 | 
42 |   return (
43 |     <section
44 |       data-voice={isVoice ? props.authorId : undefined}
45 |       className={cn(
46 |         "flex flex-col overflow-hidden rounded-xl border bg-card shadow-paper",
47 |         isVoice && "border-voice/30",
48 |       )}
49 |     >
50 |       <div className={cn("h-1 shrink-0", isVoice ? "bg-voice" : "bg-border")} />
51 | 
52 |       <header className="flex items-center justify-between gap-3 px-5 pt-4">
53 |         <span
54 |           className={cn(
55 |             "inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium",
56 |             isVoice
57 |               ? "bg-voice-tint text-voice"
58 |               : "bg-muted text-muted-foreground",
59 |           )}
60 |         >
61 |           {isVoice
62 |             ? en.studio.voiceLabel(props.authorName)
63 |             : en.studio.vanillaLabel}
64 |         </span>
65 |         {state.status === "success" && (
66 |           <span className="font-mono text-xs tabular-nums text-muted-foreground">
67 |             {en.studio.latency(state.output.latency_ms)}
68 |           </span>
69 |         )}
70 |       </header>
71 | 
72 |       <div className="flex-1 px-5 py-4">
73 |         {state.status === "loading" && (
74 |           <div role="status" className="flex flex-col gap-3">
75 |             <p className="text-sm text-muted-foreground">
76 |               {isVoice
77 |                 ? en.studio.generatingVoice(props.authorName)
78 |                 : en.studio.generating}
79 |             </p>
80 |             <div
81 |               className="flex animate-pulse flex-col gap-2"
82 |               aria-hidden="true"
83 |             >
84 |               <div className="h-3 w-full rounded bg-muted" />
85 |               <div className="h-3 w-11/12 rounded bg-muted" />
86 |               <div className="h-3 w-full rounded bg-muted" />
87 |               <div className="h-3 w-3/4 rounded bg-muted" />
88 |             </div>
89 |           </div>
90 |         )}
91 | 
92 |         {state.status === "timeout" && (
93 |           <StateNotice
94 |             icon={<Clock className="size-4 text-warning" aria-hidden="true" />}
95 |             message={en.studio.generationTimeout}
96 |             onRetry={props.onRetry}
97 |           />
98 |         )}
99 | 
100 |         {state.status === "error" && (
101 |           <StateNotice
102 |             icon={
103 |               <TriangleAlert
104 |                 className="size-4 text-destructive"
105 |                 aria-hidden="true"
106 |               />
107 |             }
108 |             message={en.studio.generationError}
109 |             onRetry={props.onRetry}
110 |           />
111 |         )}
112 | 
113 |         {state.status === "success" && (
114 |           <div className="animate-fade-rise flex flex-col gap-3">
115 |             <p className="max-w-[66ch] whitespace-pre-line font-serif text-[0.9375rem] leading-7 text-foreground/90">
116 |               {isVoice ? (
117 |                 <DistinctiveVocabHighlight
118 |                   text={state.output.text}
119 |                   terms={props.distinctiveTerms ?? []}
120 |                 />
121 |               ) : (
122 |                 state.output.text
123 |               )}
124 |             </p>
125 |             {isVoice && (props.distinctiveTerms?.length ?? 0) > 0 && (
126 |               <p className="text-xs text-muted-foreground">
127 |                 {en.studio.vocabLegend(props.authorName)}
128 |               </p>
129 |             )}
130 |           </div>
131 |         )}
132 |       </div>
133 | 
134 |       <footer className="border-t border-border/60 px-5 py-4">
135 |         {state.status === "success" ? (
136 |           isVoice ? (
137 |             <FitScoreBar
138 |               variant="authorial"
139 |               authorName={props.authorName}
140 |               score={state.output.fit_score}
141 |             />
142 |           ) : (
143 |             <FitScoreBar variant="vanilla" score={state.output.fit_score} />
144 |           )
145 |         ) : (
146 |           <FitScoreBarPending />
147 |         )}
148 |       </footer>
149 |     </section>
150 |   );
151 | }
