153 | function StateNotice({
154 |   icon,
155 |   message,
156 |   onRetry,
157 | }: {
158 |   icon: React.ReactNode;
159 |   message: string;
160 |   onRetry?: () => void;
161 | }) {
162 |   return (
163 |     <div role="status" className="flex flex-col items-start gap-3">
164 |       <p className="flex items-center gap-2 text-sm text-muted-foreground">
165 |         {icon}
166 |         {message}
167 |       </p>
168 |       {onRetry && (
169 |         <Button variant="outline" size="sm" onClick={onRetry}>
170 |           {en.studio.retry}
171 |         </Button>
172 |       )}
173 |     </div>
174 |   );
175 | }
