3 | interface DistinctiveVocabHighlightProps {
4 |   /** Generated passage text. */
5 |   text: string;
6 |   /** Terms from StyleProfile.distinctive_vocab (already ranked by the API). */
7 |   terms: readonly string[];
8 | }
9 | 
10 | function escapeRegExp(term: string): string {
11 |   return term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
12 | }
13 | 
14 | /**
15 |  * Marks the author's signature vocabulary inline using the ambient voice
16 |  * palette — an ancestor's data-voice decides the color, so this component
17 |  * stays author-agnostic. Matching is whole-word, case-insensitive.
18 |  */
19 | export function DistinctiveVocabHighlight({
20 |   text,
21 |   terms,
22 | }: DistinctiveVocabHighlightProps): ReactNode {
23 |   const patterns = terms.filter((t) => t.trim().length > 0).map(escapeRegExp);
24 |   if (patterns.length === 0) {
25 |     return text;
26 |   }
27 | 
28 |   /* Capture group makes split() interleave: even indices = plain text,
29 |      odd indices = matched terms. Unicode letter lookarounds instead of \b so
30 |      accented terms ("corazón", "María") still match whole words. */
31 |   const parts = text.split(
32 |     new RegExp(`(?<!\\p{L})(${patterns.join("|")})(?!\\p{L})`, "giu"),
33 |   );
34 | 
35 |   return parts.map((part, i) =>
36 |     i % 2 === 1 ? (
37 |       <mark
38 |         key={i}
39 |         className="rounded-sm bg-voice-tint px-0.5 font-medium text-voice"
40 |       >
41 |         {part}
42 |       </mark>
43 |     ) : (
44 |       part
45 |     ),
46 |   );
47 | }
